/*
 * @method
 * @name wavesexchange#fetchMyTrades
 * @description fetch all trades made by the user
 * @see https://api.wavesplatform.com/v0/docs/#/transactions/searchTxsExchange
 * @param {string} symbol unified market symbol
 * @param {int} [since] the earliest time in ms to fetch trades for
 * @param {int} [limit] the maximum number of trades structures to retrieve
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
 */
    pub async fn fetch_my_trades(&mut self, optional_args: &[Value]) -> Value {
        let mut symbol = get_arg(optional_args, 0, Value::Null);
        let mut since = get_arg(optional_args, 1, Value::Null);
        let mut limit = get_arg(optional_args, 2, Value::Null);
        let mut params = get_arg(optional_args, 3, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut address: Value = self.get_waves_address().await;
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("sender".to_string(), address.clone());
            m
        });
        let mut market: Value = Value::Null;
        if !is_equal(&symbol, &Value::Null) {
            market = self.market(symbol.clone());
            add_element_to_object(&mut request, &Value::Str("amountAsset".to_string()), get_value(&market, &Value::Str("baseId".to_string())));
            add_element_to_object(&mut request, &Value::Str("priceAsset".to_string()), get_value(&market, &Value::Str("quoteId".to_string())));
        }
        let mut response: Value = self.public_get_transactions_exchange(&[request.clone()]).await;
        let mut data: Value = self.safe_value_k(response.clone(), "data", &[]);
        return self.parse_trades(data.clone(), &[market.clone(), since.clone(), limit.clone()]);

    Value::Null
}

/*
 * @method
 * @name wavesexchange#fetchTrades
 * @description get the list of most recent trades for a particular symbol
 * @see https://api.wavesplatform.com/v0/docs/#/transactions/searchTxsExchange
 * @param {string} symbol unified symbol of the market to fetch trades for
 * @param {int} [since] timestamp in ms of the earliest trade to fetch
 * @param {int} [limit] the maximum amount of trades to fetch
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
 */
    pub async fn fetch_trades(&mut self, mut symbol: Value, optional_args: &[Value]) -> Value {
        let mut since = get_arg(optional_args, 0, Value::Null);
        let mut limit = get_arg(optional_args, 1, Value::Null);
        let mut params = get_arg(optional_args, 2, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut market: Value = self.market(symbol.clone());
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("amountAsset".to_string(), get_value(&market, &Value::Str("baseId".to_string())));
                m.insert("priceAsset".to_string(), get_value(&market, &Value::Str("quoteId".to_string())));
            m
        });
        if !is_equal(&limit, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("limit".to_string()), crate::runtime::Math::min(&limit, &Value::Int(100)));
        }
        if !is_equal(&since, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("timeStart".to_string()), since.clone());
        }
        let mut response: Value = self.public_get_transactions_exchange(&[request.clone()]).await;
        let mut data: Value = self.safe_value_k(response.clone(), "data", &[]);
        return self.parse_trades(data.clone(), &[market.clone(), since.clone(), limit.clone()]);

    Value::Null
}

